import{_ as a,o as s,c as i,an as t}from"./chunks/framework.Cqe3L8rE.js";const k=JSON.parse('{"title":"Benchmarking","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/benchmarking.md","filePath":"getting-started/benchmarking.md","lastUpdated":null}'),n={name:"getting-started/benchmarking.md"};function o(r,e,h,c,d,l){return s(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="benchmarking" tabindex="-1">Benchmarking <a class="header-anchor" href="#benchmarking" aria-label="Permalink to &quot;Benchmarking {#benchmarking}&quot;">​</a></h1><p>Benchmarking is opt-in. A package that ships a real performance suite enables it, and everything else skips the benchmark CI, the suite skeleton, and the benchmark docs page. This page describes what the kit sets up when benchmarks are enabled, how the two benchmark workflows differ, and how to add scenarios. See <a href="/previews/PR196/getting-started/infrastructure#infrastructure">Infrastructure and template sync</a> for the managed-versus-package-owned split.</p><h2 id="Opting-in" tabindex="-1">Opting in <a class="header-anchor" href="#Opting-in" aria-label="Permalink to &quot;Opting in {#Opting-in}&quot;">​</a></h2><p>Pass <code>benchmarks = true</code> to <code>scaffold</code> (or <code>scaffold_update</code>).</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">scaffold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pkgdir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(MyPackage); benchmarks </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>This writes the benchmark CI callers, the <code>benchmark/</code> suite skeleton, and the package-owned benchmark docs prose hook. Without the flag none of these are written, so a package that does not track performance carries no benchmark machinery at all.</p><h2 id="The-benchmark/-suite" tabindex="-1">The <code>benchmark/</code> suite <a class="header-anchor" href="#The-benchmark/-suite" aria-label="Permalink to &quot;The `benchmark/` suite {#The-benchmark/-suite}&quot;">​</a></h2><p><code>scaffold</code> lays down a <code>benchmark/</code> directory.</p><ul><li><p><code>benchmark/benchmarks.jl</code> (package-owned) defines the suite. It builds a BenchmarkTools <code>BenchmarkGroup</code> named <code>SUITE</code>, which the runners consume.</p></li><li><p><code>benchmark/run.jl</code> (managed) runs this checkout&#39;s suite and saves the results to JSON through the shared benchmark harness.</p></li><li><p><code>benchmark/compare.jl</code> (managed) builds the base-versus-head comparison comment.</p></li><li><p><code>benchmark/Project.toml</code> (package-owned) is the benchmark environment.</p></li></ul><p>You write the measurements in <code>benchmarks.jl</code> and leave the runners alone. Group evaluation benchmarks under their own keys, and put AD-gradient benchmarks under an <code>&quot;AD gradients&quot;</code> group so the comparison comment folds them into a compact per-scenario-by-backend matrix.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SUITE </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> BenchmarkGroup</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SUITE[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Evaluation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">][</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;logpdf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @benchmarkable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> logpdf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(d, x)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SUITE[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;AD gradients&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">][</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;logpdf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">][</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ForwardDiff&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @benchmarkable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> gradient</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Run the suite locally with <code>julia --project=benchmark benchmark/run.jl</code>.</p><h2 id="Two-workflows,-disjoint-triggers" tabindex="-1">Two workflows, disjoint triggers <a class="header-anchor" href="#Two-workflows,-disjoint-triggers" aria-label="Permalink to &quot;Two workflows, disjoint triggers {#Two-workflows,-disjoint-triggers}&quot;">​</a></h2><p>The kit ships two benchmark workflows that never run on the same event.</p><h3 id="PR-comparison" tabindex="-1">PR comparison <a class="header-anchor" href="#PR-comparison" aria-label="Permalink to &quot;PR comparison {#PR-comparison}&quot;">​</a></h3><p><code>benchmark.yaml</code> runs on pull requests that touch <code>src</code>, <code>ext</code>, <code>benchmark</code>, or the AD fixtures, and posts a single comparison comment. It benchmarks each revision in its own job, so the base branch runs the base branch&#39;s sources and fixtures while the pull request runs its own. That separation is what lets the AD-gradient benchmarks be compared across an API change, where staging one set of fixtures against both revisions could not. It also keeps a single runner from loading two heavy AD stacks at once.</p><p>The comparison job builds the comment through <code>EpiAwarePackageTools.Benchmarks.compare_comment</code>, which produces a bucketed summary plus collapsed detail tables split into evaluation and AD-gradient sections. The comment carries a marker so a re-run updates the existing comment rather than posting a new one.</p><h3 id="Performance-history" tabindex="-1">Performance history <a class="header-anchor" href="#Performance-history" aria-label="Permalink to &quot;Performance history {#Performance-history}&quot;">​</a></h3><p><code>benchmark-history.yaml</code> runs on pushes to <code>main</code> and on tags, and accumulates a timeline rather than posting a comment. It benchmarks the last few tagged releases plus the pushed commit with AirspeedVelocity, renders a per-benchmark plot and a ratio table, and deploys them to a dedicated <code>benchmarks</code> branch under <code>history/</code>.</p><p>The history deploy is deliberately separate from the documentation deploy. Documenter force-pushes the <code>gh-pages</code> branch on every docs build, so writing the timeline there would clobber it; a dedicated branch keeps the two independent.</p><p>The rendered timeline is spliced into the documentation site&#39;s benchmark page. That page combines a managed skeleton, your package-owned prose in <code>docs/benchmarks.md</code>, and the rendered performance history, so the narrative you write sits above the accumulated timeline.</p><h2 id="Adding-scenarios" tabindex="-1">Adding scenarios <a class="header-anchor" href="#Adding-scenarios" aria-label="Permalink to &quot;Adding scenarios {#Adding-scenarios}&quot;">​</a></h2><p>Add benchmarks by extending <code>SUITE</code> in <code>benchmark/benchmarks.jl</code>. New evaluation measurements go under an evaluation group; new gradient measurements go under the <code>&quot;AD gradients&quot;</code> group so they fold into the comparison matrix. Because the comparison workflow benchmarks each revision from its own checkout, a new scenario is measured on both sides of a pull request automatically once it is on the pull request branch. Describe what the suite covers and how to read the timeline in <code>docs/benchmarks.md</code>, which is spliced verbatim into the generated benchmark page.</p>',23)])])}const m=a(n,[["render",o]]);export{k as __pageData,m as default};
